import React,{useState} from "react";
import {useNavigate} from "react-router-dom";

export default function Login(){
const [email, setEmail] = useState("");
const [password, setPassword] = useState("");
const [error, setError] = useState("");
const navigate = useNavigate();

function handleLogin(){
if(!email || !password){
setError("Please fill all fields");
return;
}
if(email==="admin@gmail.com"&&password==="1234"){
localStorage.setItem("user", email);
navigate("/home");
setError("");
} else {
setError("Invalid credentials");
}
}

const handleKeyPress = (e) => {
if(e.key === "Enter") handleLogin();
};

return(
<div className="login-container">
<div className="row h-100 align-items-center justify-content-center">
<div className="col-md-5 col-sm-8">
<div className="login-card">
<div className="text-center mb-4">
<h1 className="login-title">
<i className="bi bi-graph-up"></i> KAS
</h1>
<p className="login-subtitle">Knowledge Analytics System</p>
</div>
<div className="login-form">
<div className="mb-3">
<label className="form-label">Email Address</label>
<input 
type="email"
className="form-control form-control-lg" 
placeholder="admin@gmail.com" 
value={email}
onChange={(e)=>setEmail(e.target.value)}
onKeyPress={handleKeyPress}
/>
</div>
<div className="mb-3">
<label className="form-label">Password</label>
<input 
type="password"
className="form-control form-control-lg" 
placeholder="Enter password" 
value={password}
onChange={(e)=>setPassword(e.target.value)}
onKeyPress={handleKeyPress}
/>
</div>
{error && <div className="alert alert-danger alert-sm">{error}</div>}
<button className="btn btn-primary btn-lg w-100 mt-3" onClick={handleLogin}>
<i className="bi bi-lock"></i> Sign In
</button>
<div className="mt-3 text-center small text-muted">
<p>Demo credentials: admin@gmail.com / 1234</p>
</div>
</div>
</div>
</div>
</div>
</div>
);
}
